-- smart-splits.nvim configuration
-- Works with Zellij via vim-zellij-navigator plugin
-- Generated by chezmoi

return {
    "mrjones2014/smart-splits.nvim",
    lazy = false,
    config = function()
        require("smart-splits").setup({
            -- Ignored filetypes (only when determining at edge)
            ignored_filetypes = {
                "nofile",
                "quickfix",
                "prompt",
                "NvimTree",
                "neo-tree",
            },
            -- Ignored buffer types
            ignored_buftypes = { "NvimTree" },
            -- Default resize amount
            default_amount = 3,
            -- At edge behavior: "wrap", "split", "stop"
            at_edge = "stop",
            -- Move cursor to same row/col in destination
            move_cursor_same_row = false,
            -- Disable mapping buffer-local filetypes
            cursor_follows_swapped_bufs = false,
            -- Multiplexer integration (auto-detect: tmux, wezterm, kitty, zellij)
            multiplexer_integration = nil,
            -- Resize mode options
            resize_mode = {
                quit_key = "<ESC>",
                resize_keys = { "h", "j", "k", "l" },
                silent = false,
                hooks = {
                    on_enter = nil,
                    on_leave = nil,
                },
            },
        })

        local ss = require("smart-splits")

        -- ═══════════════════════════════════════════════════════════════════
        -- NAVIGATION (Ctrl+hjkl)
        -- These cross Neovim ↔ Zellij boundaries via vim-zellij-navigator
        -- ═══════════════════════════════════════════════════════════════════
        vim.keymap.set({ "n", "t" }, "<C-h>", ss.move_cursor_left, { desc = "Move cursor left (cross-boundary)" })
        vim.keymap.set({ "n", "t" }, "<C-j>", ss.move_cursor_down, { desc = "Move cursor down (cross-boundary)" })
        vim.keymap.set({ "n", "t" }, "<C-k>", ss.move_cursor_up, { desc = "Move cursor up (cross-boundary)" })
        vim.keymap.set({ "n", "t" }, "<C-l>", ss.move_cursor_right, { desc = "Move cursor right (cross-boundary)" })

        -- ═══════════════════════════════════════════════════════════════════
        -- RESIZE (Alt+hjkl) - Neovim splits only, not Zellij panes
        -- Use Alt+Shift+HJKL in Zellij for pane resizing
        -- ═══════════════════════════════════════════════════════════════════
        vim.keymap.set("n", "<A-h>", ss.resize_left, { desc = "Resize split left" })
        vim.keymap.set("n", "<A-j>", ss.resize_down, { desc = "Resize split down" })
        vim.keymap.set("n", "<A-k>", ss.resize_up, { desc = "Resize split up" })
        vim.keymap.set("n", "<A-l>", ss.resize_right, { desc = "Resize split right" })

        -- ═══════════════════════════════════════════════════════════════════
        -- SWAP BUFFERS (<leader>s + hjkl)
        -- ═══════════════════════════════════════════════════════════════════
        vim.keymap.set("n", "<leader>sh", ss.swap_buf_left, { desc = "Swap buffer left" })
        vim.keymap.set("n", "<leader>sj", ss.swap_buf_down, { desc = "Swap buffer down" })
        vim.keymap.set("n", "<leader>sk", ss.swap_buf_up, { desc = "Swap buffer up" })
        vim.keymap.set("n", "<leader>sl", ss.swap_buf_right, { desc = "Swap buffer right" })
    end,
}
